script.text:

/* <flatten type="Javascript"> */
function load$GridVoucherDetail$(g) {
  g.add_itemValueChanged(onChange$GridVoucherDetail$);
  g.add_onResponseComplete(on$GridVoucherDetail$ResponseComplete);
  g.add_commandEvent(on$GridVoucherDetail$ExecuteCommand);
  g.$a = {
    gia_nt_sl: '[gia_nt]:=([gia_nt] == 0 ? ([so_luong] != 0 ? ([tien_nt]/[so_luong]) : 0) : [gia_nt])',
    gia_sl: '[gia]:=([gia] == 0 ? ([so_luong] != 0 ? ([tien]/[so_luong]) : 0) : [gia])',

    gia: '[gia]:=[gia_nt]*[$ty_gia]',
    tien_nt: '[tien_nt]:=[so_luong]*[gia_nt]',
    tien: '[tien]:=[so_luong]*[gia]',
    tien_tg: '[tien]:=[tien_nt]*[$ty_gia]',

    t_so_luong: ['t_so_luong', 'so_luong'],
    t_tien_nt: ['t_tien_nt', 'tien_nt'],
    t_tien: ['t_tien', 'tien']
  };
  g.$h = [['voucherCode', 'String', g._voucherCode], 'ma_dvcs'];
  udf$Detail$(g);
}
function dispose$GridVoucherDetail$(g) {
  g.$a = null;
  try {g.remove_commandEvent(on$GridVoucherDetail$ExecuteCommand);} catch (ex) {}
  try {g.remove_onResponseComplete(on$GridVoucherDetail$ResponseComplete);} catch (ex) {}
  try {g.remove_itemValueChanged(onChange$GridVoucherDetail$);} catch (ex) {}
}
function onChange$GridVoucherDetail$Item(o) {o.grid.request(o, 'Item', 'Item', ['ma_vt', 'ma_kho'], o.grid.$h, true);}
function onChange$GridVoucherDetail$UOM(o) {o.grid.request(o, 'UOM', 'UOM', ['ma_vt', 'ma_kho', 'dvt', 'so_luong'], o.grid.$h, true);}
function onChange$GridVoucherDetail$Site(o) {o.grid.request(o, 'Site', 'Site', ['ma_vt','ma_kho'], o.grid.$h, true);}
function onChange$GridVoucherDetail$CreditAccount(o) {o.grid.request(o, 'Reason', 'Reason', ['ma_nx'], o.grid.$h, true);}
function onChange$GridVoucherDetail$(sender, eventArgs) {
  var o = eventArgs.get_object(), g = o.grid, f = g.get_element().parentForm, name = o.field.Name;
  switch (name) {
    case 'so_luong':
      g.validExpression(o, [g.$a.tien_nt, g.$a.tien], [g.$a.t_so_luong, g.$a.t_tien_nt, g.$a.t_tien]);
      break;
    case 'gia_nt':
      g.validExpression(o, [g.$a.gia, g.$a.tien_nt, g.$a.tien], [g.$a.t_tien_nt, g.$a.t_tien], null, 'tien_nt');
      break;
    case 'tien_nt':
      if (f._calPrice) g.validExpression(o, [g.$a.gia_nt_sl, g.$a.gia]);
      g.validExpression(o, [g.$a.tien, g.$a.tien_tg], [g.$a.t_tien_nt, g.$a.t_tien]);
      break;
    case 'gia':
      g.validExpression(o, [g.$a.tien], [g.$a.t_tien], null, 'tien');
      break;
    case 'tien':
      if (f._calPrice) g.validExpression(o, [g.$a.gia_sl]);
      g.validExpression(o, null, [g.$a.t_tien]);
      break;
    default:
      break;
  }
}
/* </flatten> */
function on$GridVoucherDetail$ExecuteCommand(sender, e) {
  var action = e.type.Action, g = sender, f = g.get_element().parentForm, type = ($func.trim(f.getItemValue('loai_ct')) == '3');
  switch (action) {&ScriptCheckGridAction;
    case 'AfterRemoveRow':
      on$GridVoucherDetail$RowChange(g, f);
      break;
    case 'AfterCloneRow':
      g.setItemFieldValue('stt_rec0', e.type.Value, '');
      on$GridVoucherDetail$RowChange(g, f);
      break;
    case 'AfterInsertRow':
      g._setItemValue(g._rowCount, g._getColumnOrder('tk_du'), f._refAccount);
      g._setItemValue(g._rowCount, g._getColumnOrder('ma_nx'), f._reasonCode);
      break;
    case 'Check':
      if (type && !(g.validRowExpression('pn_gia_tb', '(![pn_gia_tb])'))) break;
      if (!type && !(g.validRowExpression('nm_so', '([nm_so] == "")'))) break;
      if (type && !(g.validRowExpression('wh_so', '([wh_so] == "")'))) break;
      if (!(g.validRowExpression('so_luong', '([gia_ton] != 3) || ([gia_ton] == 3 && [so_luong] != 0)'))) break;
      if (g._tracked$Lot && !(g.validRowExpression('ma_lo', '(![lo_yn]) || ([ma_lo] != "")'))) break;
      if (g._tracked$Location) g.validRowExpression('ma_vi_tri', '(![vi_tri_yn]) || ([ma_vi_tri] != "")');
      break;
&AutoLotGrid;
    case 'ImportData':
      if (f._action == 'View') break;
      g.showForm('IRDetailImport');
      break;
    case 'Download':
      request$Download(g, action);
      break;
    case 'Retrieve':
      if (f._action == 'View') break;
      if (!f.validFields('ngay_lct')) break;
        switch (e.type.Value) {
          case '10':
            if (type || !g._tracked) break;
            g.showForm('IRPhysicalFilter');
            break;
          case '30':
            if (!type || !f.validFields('ma_kh')) break;
            g.showForm('IRReceiptFilter');
            break;
          default:
            break;
        }
      break;
    case 'Copying':
      var fields = '';
      if (g._getColumnOrder('stt_rec_nm') >= 0) fields = 'nm_so, nm_ln, stt_rec_nm, stt_rec0nm';
      if (g._getColumnOrder('sl_hd') >= 0) fields += (fields != '' ? ', ' : '') + 'sl_hd';
&ScriptWhenTransactionEmptyField;
      if (fields != '') set$Voucher$EmptyExternalField(g, fields);
      break;
    default:
      break;
  }
}
/* <flatten type="Javascript"> */
function on$GridVoucherDetail$ResponseComplete(sender, e) {
 var g = e.object, context = e.type.Context, result = e.type.Result, o = e.type.Object, f = g.get_element().parentForm;
  switch (context) {
    case 'Item':
      var v = (result[0].Value == '' ? true : null), t = (result[0].Value == '' ? 'false' : 'true');
      g.setItemGridBehavior(o, [
        ['ma_lo', '', null, null],
        ['ma_kho', result[0].Value, '', true],
        ['ma_vi_tri', result[1].Value, '', v],
        ['dvt', result[2].Value, '', true],
        ['he_so', result[3].Value, null, null],
        ['tk_vt', result[4].Value, '', true],
        ['gia_ton', result[5].Value, null, null],
        ['vi_tri_yn', [result[6].Value, t], null, null],
        ['lo_yn', result[7].Value, null, null],
        ['tao_lo', result[10].Value, null, null]
      ]);
      g.live(o, 'dvt');
      break;
    case 'UOM':
      g.setItemGridBehavior(o, [['he_so', result[0].Value, '', true]]);
      break;
    case 'Site':
      g.setItemGridBehavior(o, [['tk_vt', result[0].Value, '', true], ['ma_vi_tri', '', '', null], ['vi_tri_yn', result[1].Value, null, null]]);
      break;
    case 'Reason':
      g.setItemGridBehavior(o, [['tk_du', result[0].Value, '', true]]);
      break;
    case 'Download':
      g._key = result[0].Value;
      break;
    default:
      break;
  }
}
function on$GridVoucherDetail$RowChange(g, f) {g.executeAggregate([g.$a.t_so_luong, g.$a.t_tien_nt, g.$a.t_tien]);}
/* </flatten> */
      &ScriptInsertRetrieveItems;
